import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { addNotification } from "../notificationReducer";

function AddCourse() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector((state) => state.auth.user);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [file, setFile] = useState(null);

  async function handleSubmit(e) {
    e.preventDefault();
    const formData = new FormData();
    formData.append("file", file);
    formData.append("courseData", JSON.stringify({ name, description, teacherId: user.id }));

    const response = await fetch("http://localhost:3001/courses", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, description, teacherId: user.id }),
    });

    if (response.ok) {
      const course = await response.json();
      if (file) {
        const fileFormData = new FormData();
        fileFormData.append("file", file);
        const fileResponse = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: fileFormData,
        });
        if (fileResponse.ok) {
          const { filePath } = await fileResponse.json();
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: course.id,
              fileName: file.name,
              filePath,
            }),
          });
        }
      }
      dispatch(addNotification({
        id: Date.now(),
        userId: user.id,
        message: `Course ${name} created!`,
        createdAt: new Date().toISOString(),
      }));
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Course ${name} created!`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Course created successfully!");
      navigate("/courses");
    } else {
      toast.error("Failed to create course.");
    }
  }

  return (
    <div className="page-container">
      <div className="form-container">
        <h1>Create a Course (Teachers Only)</h1>
        <div className="form-container">
          <input
            type="text"
            placeholder="Course Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
          <input
            type="text"
            placeholder="Description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
          />
          <input
            type="file"
            onChange={(e) => setFile(e.target.files[0])}
            accept=".pdf,.docx,.jpg,.png"
          />
          <button onClick={handleSubmit}>Create Course</button>
        </div>
      </div>
    </div>
  );
}

export default AddCourse;
